/* ---------------- Small components ---------------- */
function SectionHead({ eyebrow, title }) {
  return (
    <div className="mb-12">
      <div className="flex items-center gap-2 text-cyan-400 font-mono text-xs tracking-widest mb-3">
        <span className="w-1.5 h-1.5 rounded-full bg-cyan-400 animate-pulse" />
        {eyebrow}
      </div>
      <h2 className="text-3xl md:text-4xl font-bold text-slate-100 tracking-tight">{title}</h2>
      <div className="w-14 h-0.5 bg-gradient-to-r from-blue-500 to-purple-500 mt-4" />
    </div>
  );
}

function Reveal({ children, className = "" }) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold: 0.12 }
    );
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div
      ref={ref}
      className={`transition-all duration-700 ease-out ${visible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-6"} ${className}`}
    >
      {children}
    </div>
  );
}

